  $t = ($_ -replace '\(.*', '').Trim()
  $t -split ';' | ForEach-Object { $_.Trim() }
} | Where-Object { $_ -and ($_ -notmatch '^\(.*\)$') -and ($_ -match '^(M|G)\d+\b') })

$port = New-Object System.IO.Ports.SerialPort $Com, 115200, None, 8, One
$port.DtrEnable = $false
$port.RtsEnable = $false
$port.ReadTimeout = 4500
$port.WriteTimeout = 4500
try {
  $port.Open()
} catch {
  Write-Host $_
  Write-Host "Disconnect Candle on $Com , then rerun."
  exit 1
}

Start-Sleep -Milliseconds 2000

function Read-Responses([System.IO.Ports.SerialPort]$p, $deadlineMs, [ref]$combined) {
  $deadline = [datetime]::UtcNow.AddMilliseconds($deadlineMs)
  while ([datetime]::UtcNow -lt $deadline -or $p.BytesToRead -gt 0) {
    try {
      while ($p.BytesToRead -gt 0) {
        $chunk = $p.ReadExisting()
        $combined.Value += $chunk
        if ($combined.Value -match '(?ms)ALARM:|error:|\r\nok\r\n?$') {
          break
        }
      }
    } catch { }
    if ($combined.Value -match '(?ms)ALARM:|error:|^ok\b') { break }
    Start-Sleep -Milliseconds 35
    if (-not ([datetime]::UtcNow -lt $deadline)) { break }
  }
}

function Send-Line([System.IO.Ports.SerialPort]$p, [string]$s) {
  $p.DiscardInBuffer()
  $buf = ''
  Read-Responses $p 80 ([ref]$buf) | Out-Null

  $line = "$s "
  $ascii = ([regex]::Matches($line, '[\x00-\x7F]' ) | ForEach-Object { [byte][char]$_.Value })
  # GRBL prefers short lines ending CR-LF acceptable
  $bytes = New-Object byte[] (($ascii.Length) + 1)
  [array]::Copy($ascii, $bytes, $ascii.Length)
  $bytes[$ascii.Length] = [byte][char]13
  $p.Write($bytes, 0, $bytes.Length)

  $combined = ''
  Read-Responses $p 9500 ([ref]$combined)

  # Next status poll after motion-heavy lines occasionally returns grbl buffering 'ok'; treat ok as success
  if ($combined -match 'ALARM:') {
    Write-Host "`n<<< $combined"
    throw "STOP: Alarm"
  }
  if ($combined -match 'error:') {
    Write-Host "`n<<< $combined"
    throw "STOP: Controller error"
  }
  Write-Host ".$($s.Substring(0, [Math]::Min(55, $s.Length))) ..."
}

Send-Line $port '?'
Try { Send-Line $port '$X' } Catch { Write-Host "`$X not accepted (may already be Idle): $_" }

try {
  foreach ($ln in $lines) {
    if ($ln -match '^\(.*\)|^$') { continue }
    Send-Line $port ([string]$ln).TrimEnd()
  }
  Send-Line $port '?'
} finally {
  $port.Close()
  $port.Dispose()
}

Write-Host "`nDry-run streaming finished."

