function Try-Poll-Homing {
  $com = 'COM7'
  $sp = New-Object System.IO.Ports.SerialPort $com, 115200, None, 8, One
  $sp.DtrEnable = $false; $sp.RtsEnable = $false
  try { $sp.Open() } catch { return ($_.Exception.Message) }
  Write-Host "--- COM open: polling every 400 ms for ~80 s ---"
  $deadline = (Get-Date).AddSeconds(80)
  $last = ''
  Start-Sleep -Milliseconds 1600

  while ((Get-Date) -lt $deadline) {
    try {
      $sp.DiscardInBuffer()
      $b = [System.Text.Encoding]::ASCII.GetBytes('?' + [char]13)
      $sp.Write($b, 0, $b.Length)
      Start-Sleep -Milliseconds 120
      $acc = ''; $twait = (Get-Date).AddMilliseconds(950)
      while ((Get-Date) -lt $twait -or $sp.BytesToRead) {
        if ($sp.BytesToRead) { $acc += $sp.ReadExisting() }
        Start-Sleep -Milliseconds 25
        if ($acc -match 'ok\s*$|[\x3c](?:Idle|Alarm|Run|Hold|Door|Home|Sleep|Check)') { break }
      }
      # One-line summary: strip newlines noise
      $line = (($acc.Trim() -replace '\s+',' '()))
      $status = ([regex]::Match($line,'<[^>]+>')).Value
      $time = Get-Date -Format 'HH:mm:ss.fff'
      if (-not [string]::IsNullOrWhiteSpace($line) -and $line -ne $last) {
        Write-Host "[$time] $line"
        $script:last = $line
      }
    } catch {
      Write-Host "Poll error: $_"
      break
    }
    Start-Sleep -Milliseconds (400 - 120)
  }

  $sp.Close(); $sp.Dispose()
  Write-Host "--- Poll done ---"
  return $null
}

